class UnionFind:
    def __init__(self, n):
        self.parent = list(range(n))
        self.rank = [0] * n
        self.count = n

    def find(self, x):
        if self.parent[x] != x:
            self.parent[x] = self.find(self.parent[x])  # Path compression
        return self.parent[x]

    def union(self, x, y):
        root_x = self.find(x)
        root_y = self.find(y)

        if root_x != root_y:
            if self.rank[root_x] < self.rank[root_y]:
                self.parent[root_x] = root_y
            elif self.rank[root_x] > self.rank[root_y]:
                self.parent[root_y] = root_x
            else:
                self.parent[root_y] = root_x
                self.rank[root_x] += 1
            self.count -= 1

    def connected(self, x, y):
        return self.find(x) == self.find(y)

    def get_count(self):
        return self.count

if __name__ == '__main__':
    # Example usage:
    n = 10  # Number of elements
    uf = UnionFind(n)

    # Perform some union operations
    uf.union(0, 1)
    uf.union(2, 3)
    uf.union(4, 5)
    uf.union(6, 7)
    uf.union(8, 9)
    uf.union(0, 2)
    uf.union(4, 6)

    # Check if elements are connected
    print(f"0 and 3 are connected: {uf.connected(0, 3)}")  # Output: True
    print(f"1 and 5 are connected: {uf.connected(1, 5)}")  # Output: False

    # Get the number of connected components
    print(f"Number of connected components: {uf.get_count()}") # Output: 3
